    37		FULL        // + start_column, end_column
    38	};
    39	
    40	enum class StructureLevel : uint8_t {
    41		NONE = 0, // No tree structure info
    42		MINIMAL,  // + parent_id, depth, sibling_index (O(1) fields)
    43		FULL      // + children_count, descendant_count (O(child_count) fields)
    44	};
    45	
    46	enum class PeekLevel : uint8_t {
    47		NONE = 0, // No source preview
    48		SMART,    // Adaptive preview based on node type
    49		FULL,     // Complete source text for node
    50		CUSTOM    // Fixed character limit (specified separately)
    51	};
    52	
    53	//==============================================================================
    54	// Organized Field Groups
    55	//==============================================================================
    56	
    57	struct SourceLocation {
    58		string file_path;      // Available if location >= INPUT_ONLY
    59		string language;       // Available if location >= INPUT_ONLY
    60		uint32_t start_line;   // Available if location >= LINES
    61		uint32_t end_line;     // Available if location >= LINES
    62		uint32_t start_column; // Available if location >= FULL
    63		uint32_t end_column;   // Available if location >= FULL
    64	
    65		// Default constructor
    66		SourceLocation() : start_line(0), end_line(0), start_column(0), end_column(0) {
    67		}
    68	};
