    71		int64_t parent_id;         // Available if structure >= MINIMAL (O(1))
    72		uint32_t depth;            // Available if structure >= MINIMAL (O(1))
    73		uint32_t sibling_index;    // Available if structure >= MINIMAL (O(1))
    74		uint32_t children_count;   // Available if structure >= FULL (O(child_count))
    75		uint32_t descendant_count; // Available if structure >= FULL (O(child_count))
