   142			return source.end_column;
   143		}
   144		int64_t get_parent_id() const {
   145			return structure.parent_id;
   146		}
   147		uint32_t get_depth() const {
   148			return structure.depth;
   149		}
   150		uint32_t get_children_count() const {
   151			return structure.children_count;
   152		}
   153		uint32_t get_descendant_count() const {
   154			return structure.descendant_count;
   155		}
   156		string get_name() const {
   157			return context.name;
   158		}
   159		uint8_t get_semantic_type() const {
