    12	// Helper function to detect if a function/method node has a body child
    13	// Used for runtime detection of abstract methods in languages like Java where
    14	// the same node type (method_declaration) is used for both abstract and concrete methods
    15	static bool HasBodyChild(TSNode node) {
    16		// Common body child types across languages
    17		static const char *body_types[] = {"block",              // Java, Python, Go, Rust, C#
    18		                                   "compound_statement", // C, C++, PHP
    19		                                   "statement_block",    // JavaScript, TypeScript
    20		                                   "function_body",      // Dart, some languages
    21		                                   "body",               // Generic
    22		                                   "body_statement",     // Ruby
    23		                                   "braced_expression",  // R
    24		                                   "constructor_body",   // Java constructors
    25		                                   nullptr};
    26	
    27		uint32_t child_count = ts_node_named_child_count(node);
    28		for (uint32_t i = 0; i < child_count; i++) {
    29			TSNode child = ts_node_named_child(node, i);
    30			const char *child_type = ts_node_type(child);
    31	
    32			// Check against known body types
    33			for (const char **body_type = body_types; *body_type != nullptr; body_type++) {
    34				if (strcmp(child_type, *body_type) == 0) {
    35					return true;
    36				}
    37			}
    38		}
    39		return false;
    40	}
