    42	// Helper function to ensure UTF-8 validity using DuckDB's UTF8 processor
    43	static string SanitizeUTF8(const string &input) {
    44		if (input.empty()) {
    45			return input;
    46		}
    47	
    48		// Check if already valid
    49		if (Utf8Proc::IsValid(input.c_str(), input.size())) {
    50			return input;
    51		}
    52	
    53		// Create mutable char array for MakeValid (following DuckDB pattern)
    54		std::vector<char> char_array(input.begin(), input.end());
    55		char_array.push_back('\0');                                      // Null-terminate
    56		Utf8Proc::MakeValid(&char_array[0], char_array.size() - 1, '?'); // Replace invalid bytes with '?'
    57		return string(char_array.begin(), char_array.end() - 1);         // Exclude null terminator
    58	}
