    60	// Template implementation with ExtractionConfig - eliminates virtual calls
    61	template <typename AdapterType>
    62	ASTResult UnifiedASTBackend::ParseToASTResultTemplated(const AdapterType *adapter, const string &content,
    63	                                                       const string &language, const string &file_path,
    64	                                                       const ExtractionConfig &config) {
    65		ASTResult result;
    66		result.source.file_path = file_path;
    67		result.source.language = language;
    68		auto start_time = std::chrono::system_clock::now();
    69	
    70		// === TREE-SITTER MEMORY PHASE BEGIN ===
    71		// Parse the content using the adapter's smart pointer wrapper
    72		TSTreePtr tree = adapter->ParseContent(content);
    73		if (!tree) {
    74			throw InternalException("Failed to parse content");
    75		}
    76	
    77		// MEMORY SAFETY: All TSNode objects are lightweight references into tree-sitter memory.
    78		// ALL extracted VALUES must be immediately copied when stored in ASTNode fields.
    79		// NO TSNode references should escape this function scope.
    80	
    81		// Process tree into ASTNodes using DFS ordering with O(1) descendant counting
    82		TSNode root = ts_tree_root_node(tree.get());
    83		uint32_t max_depth = 0;
    84	
    85		struct StackEntry {
    86			TSNode node;
    87			int64_t parent_id;
    88			uint32_t depth;
    89			uint32_t sibling_index;
    90			bool processed;   // Track if node has been processed
    91			idx_t node_index; // Index in nodes array for this node
    92		};
    93	
    94		// Hoist GetNodeConfigs outside the hot loop - huge performance optimization!
    95		const auto &node_configs = adapter->GetNodeConfigs();
    96	
    97		vector<StackEntry> stack;
    98		stack.push_back({root, -1, 0, 0, false, 0});
