   215							ast_node.peek =
   216							    SanitizeUTF8(source_text.length() > 80 ? source_text.substr(0, 77) + "..." : source_text);
   217						} else {
   218							// Multi-line: first meaningful line with smart truncation
   219							size_t newline_pos = source_text.find('\n');
   220							string first_line = source_text.substr(0, newline_pos);
   221							ast_node.peek =
   222							    SanitizeUTF8(first_line.length() > 80 ? first_line.substr(0, 77) + "..." : first_line);
   223						}
   224					} else if (config.peek == PeekLevel::CUSTOM) {
   225						// Custom size mode
   226						uint32_t effective_size = config.peek_size > 0 ? config.peek_size : 120;
   227						ast_node.peek = SanitizeUTF8(
   228						    source_text.length() > effective_size ? source_text.substr(0, effective_size) : source_text);
   229					} else {
   230						// Default fallback (shouldn't happen)
   231						ast_node.peek = SanitizeUTF8(source_text.length() > 120 ? source_text.substr(0, 120) : source_text);
   232					}
   233				}
   234	
   235				// Populate semantic type and other fields - pass configs to avoid virtual call
   236				// Only populate semantic fields based on config.context level
   237				if (config.context >= ContextLevel::NODE_TYPES_ONLY) {
   238					PopulateSemanticFieldsTemplated(ast_node, adapter, entry.node, content, node_configs, config);
   239				} else {
   240					// No context info - set minimal defaults (use flat fields)
   241					ast_node.semantic_type = 0;
   242					ast_node.universal_flags = 0;
   243					ast_node.arity_bin = 0;
   244					ast_node.type_normalized = "";
   245					ast_node.native_extraction_attempted = false;
   246				}
