// Compute breadcrumb qualified_name during tree walk.
// - Root/file node gets qualified_name = filename.
// - Any named node gets qualified_name = parent_scope::node_name.
// - Only DEFINITION-type nodes advance the scope for their children;
//   call nodes, references, etc. do not create new scope levels.
string child_scope = entry.scope; // default: children inherit parent scope
if (config.context >= ContextLevel::NORMALIZED) {
	string node_qname;
	if (entry.depth == 0) {
		// Root/file node: qualified_name is the filename itself
		node_qname = entry.scope;
	} else if (!ast_node.name_raw.empty()) {
		// Named node: append name to parent scope
		node_qname = entry.scope + "::" + ast_node.name_raw;
	}
	if (!node_qname.empty()) {
		ast_node.native.qualified_name = node_qname;
	}
	// Advance scope only for definition nodes (functions, classes, modules)
	// and for the root node. Other named nodes (calls, references) stay at
	// their enclosing definition scope.
	bool is_def = !ast_node.name_raw.empty() &&
	              (ast_node.semantic_type & 0xF0) == SemanticTypes::DEFINITION;
	if (entry.depth == 0 || is_def) {
		child_scope = node_qname.empty() ? entry.scope : node_qname;
	}
}

